1	#ifndef JTAG_DTM_HPP
2	#define JTAG_DTM_HPP
3	
4	#include "utils/ahb.hpp"
5	
6	#include <boost/asio.hpp>
7	#include <spdlog/spdlog.h>
8	#include <systemc>
9	
10	#include <cstdint>
11	
12	#include <string_view>
13	#include <system_error>
14	
15	namespace asio = boost::asio;
16	namespace ip = asio::ip;
17	using asio::ip::tcp;
18	
19	enum class jtag_state
20	{
21	  test_logic_reset,
22	  run_test_idle,
23	  select_dr_scan,
24	  capture_dr,
25	  shift_dr,
26	  exit1_dr,
27	  pause_dr,
28	  exit2_dr,
29	  update_dr,
30	  select_ir_scan,
31	  capture_ir,
32	  shift_ir,
33	  exit1_ir,
34	  pause_ir,
35	  exit2_ir,
36	  update_ir,
37	};
38	
39	enum class jtag_ir : uint8_t
40	{
41	  idcode = 0x1,
42	  dtmcs = 0x10,
43	  dmi = 0x11,
44	  bypass = uint8_t(-1),
45	};
46	
47	constexpr auto jtag_state_transitions =
48	  std::array<std::array<jtag_state, 2>, 16>{{
49	    // clang-format off
50	    {jtag_state::run_test_idle, jtag_state::test_logic_reset}, // test_logic_reset
51	    {jtag_state::run_test_idle, jtag_state::select_dr_scan}, // run_test_idle
52	    {jtag_state::capture_dr, jtag_state::select_ir_scan}, // select_dr_scan
53	    {jtag_state::shift_dr, jtag_state::exit1_dr}, // capture_dr
54	    {jtag_state::shift_dr, jtag_state::exit1_dr}, // shift_dr
55	    {jtag_state::pause_dr, jtag_state::update_dr}, // exit1_dr
56	    {jtag_state::pause_dr, jtag_state::exit2_dr}, // pause_dr
57	    {jtag_state::shift_dr, jtag_state::update_dr}, // exit2_dr
58	    {jtag_state::run_test_idle, jtag_state::select_dr_scan}, // update_dr
59	    {jtag_state::capture_ir, jtag_state::test_logic_reset}, // select_ir_scan
60	    {jtag_state::shift_ir, jtag_state::exit1_ir}, // capture_ir
61	    {jtag_state::shift_ir, jtag_state::exit1_ir}, // shift_ir
62	    {jtag_state::pause_ir, jtag_state::update_ir}, // exit1_ir
63	    {jtag_state::pause_ir, jtag_state::exit2_ir}, // pause_ir
64	    {jtag_state::shift_ir, jtag_state::update_ir}, // exit2_ir
65	    {jtag_state::run_test_idle, jtag_state::select_dr_scan} // update_ir
66	    // clang-format on
67	  }}; // update_ir
68	
69	enum class dmi_op_operation
70	{
71	  nop = 0,
72	  read = 1,
73	  write = 2,
74	  reserved = 3,
75	};
76	
77	constexpr static inline auto
78	to_string(const dmi_op_operation op) -> std::string_view
79	{
80	  switch (op) {
81	  case dmi_op_operation::nop:
82	    return "nop";
83	  case dmi_op_operation::read:
84	    return "read";
85	  case dmi_op_operation::write:
86	    return "write";
87	  case dmi_op_operation::reserved:
88	    return "reserved";
89	  default:
90	    __builtin_unreachable();
91	  }
92	}
93	
94	enum class dmi_op_status
95	{
96	  success = 0,
97	  reserved = 1,
98	  failed = 2,
99	  busy = 3,
100	};
101	
102	constexpr static inline auto
103	to_string(const dmi_op_status status) -> std::string_view
104	{
105	  switch (status) {
106	  case dmi_op_status::success:
107	    return "success";
108	  case dmi_op_status::reserved:
109	    return "reserved";
110	  case dmi_op_status::failed:
111	    return "failed";
112	  case dmi_op_status::busy:
113	    return "busy";
114	  default:
115	    __builtin_unreachable();
116	  }
117	}
118	struct jtag_dtm : sc_core::sc_module
119	{
120	  // (mfg: 0x31e (Andes Technology Corporation), part: 0x0005, ver: 0x1)
121	  static constexpr auto idcode = 0x1000563d;
122	  static constexpr auto ir_length = 5;
123	  static constexpr auto abits = 7;
124	
125	  using ahb_manager = ahb::manager<abits + 2, 32>;
126	
127	  ahb_manager& ahb;
128	
129	  std::optional<tcp::socket> socket{};
130	  tcp::acceptor acceptor{asio::system_executor{}};
131	  std::array<char, 4096> recv_buf_array{};
132	  std::span<char> recv_buf{};
133	
134	  jtag_state state;
135	  bool tck, tdo;
136	  // two shift registers : ir, dr
137	  jtag_ir ir;
138	  uint64_t dr;
139	  size_t dr_length;
140	  uint32_t dtmcs;
141	  uint64_t dmi;
142	
143	  sc_core::sc_in<bool> clk{"clk"};
144	  using SC_CURRENT_USER_MODULE = jtag_dtm;
145	
146	  void hardreset()
147	  {
148	    // spdlog::trace("DTMCS hardreset");
149	    state = jtag_state::test_logic_reset;
150	    tck = false, tdo = false;
151	    ir = jtag_ir::idcode;
152	    dr = 0;
153	    dr_length = 64;
154	    // version (0: v0.11, 1: v0.13 and v1.0)
155	    // idle (stay in idle mode for 6 cycles in each scan)
156	    dtmcs = uint32_t(1) << 0 // version
157	          | uint32_t(abits) << 4 // abits
158	          | uint32_t(7) << 12; // idle
159	    static_assert(34 + abits <= 64);
160	    dmi = 0;
161	    recv_buf_array = {};
162	    recv_buf = {};
163	    if (this->socket && this->socket->is_open()) {
164	      this->socket->shutdown(boost::asio::ip::tcp::socket::shutdown_both);
165	      this->socket->close();
166	      this->socket = std::nullopt;
167	    }
168	  }
169	
170	  jtag_dtm(const sc_core::sc_module_name& name, ahb_manager& ahb)
171	      : sc_core::sc_module{name}, ahb{ahb}
172	  {
173	    hardreset();
174	    SC_METHOD(tick);
175	    this->sensitive << clk.pos();
176	  }
177	
178	  void init_port(const uint16_t port)
179	  {
180	    const auto endpoint = tcp::endpoint(ip::make_address("127.0.0.1"), port);
181	    this->acceptor.open(endpoint.protocol());
182	    this->acceptor.set_option(tcp::acceptor::reuse_address(true));
183	    // TODO: change it to blocking mode ?
184	    this->acceptor.non_blocking(true);
185	    this->acceptor.bind(endpoint);
186	    this->acceptor.listen();
187	    spdlog::info("jtag_dtm: listening on 127.0.0.1:{}", port);
188	  }
189	
190	  [[nodiscard]]
191	  auto is_connected() const -> bool
192	  {
193	    return this->socket.has_value();
194	  }
195	
196	  void handle_dmi_status()
197	  {
198	    if (this->ahb.txn.is_busy()) {
199	      this->dmi = uint64_t(dmi_op_status::busy);
200	    } else if (this->ahb.txn.phase == ahb_manager::transaction::phase::error) {
201	      this->dmi = uint64_t(dmi_op_status::failed);
202	    } else {
203	      this->dmi = uint64_t(dmi_op_status::success);
204	    }
205	    this->dmi |= (uint64_t(this->ahb.txn.addr) >> 2) << 34
206	               | uint64_t(this->ahb.txn.data) << 2;
207	    // spdlog::trace("dmi: status={}, addr={:#x}, data={:#x}", this->dmi & 0b11,
208	    // this->ahb.txn.addr.to_uint64() >> 2,
209	    // this->ahb.txn.data.to_uint64());
210	  }
211	  void handle_dmi_op()
212	  {
213	    this->dmi = this->dr;
214	    const auto op = this->dmi & 0b11;
215	    const auto data = (this->dmi >> 2) & 0xffffffff;
216	    const auto addr = (this->dmi >> 34) & ((uint64_t{1} << abits) - 1);
217	    // spdlog::trace("dmi: op={}, addr={:#x}, data={:#x}", op, addr, data);
218	    if (op == 1) { // read
219	      assert(!this->ahb.txn.is_busy());
220	      this->ahb.read(addr << 2);
221	    } else if (op == 2) { // write
222	      assert(!this->ahb.txn.is_busy());
223	      ahb.write(addr << 2, data);
224	    }
225	  }
226	
227	  void set_tck_tms_tdi(const bool tck, const bool tms, const bool tdi)
228	  {
229	    if (tck == this->tck)
230	      return;
231	
232	    this->tck = tck;
233	
234	    if (tck) { // rising edge
235	      if (this->state == jtag_state::shift_ir) {
236	        this->ir = jtag_ir((uint8_t) (uint8_t(this->ir) >> 1)
237	                           | (uint8_t(tdi) << (ir_length - 1)));
238	      } else if (this->state == jtag_state::shift_dr) {
239	        this->dr = (this->dr >> 1) | (uint64_t(tdi) << (dr_length - 1));
240	      }
241	      this->state = jtag_state_transitions[size_t(this->state)][size_t(tms)];
242	    } else { // falling edge
243	      if (this->state == jtag_state::test_logic_reset) {
244	        // spdlog::trace("test_logic_reset");
245	        this->ir = jtag_ir::idcode;
246	      } else if (this->state == jtag_state::run_test_idle) {
247	        // spdlog::debug("run_test_idle");
248	      } else if (this->state == jtag_state::capture_dr) {
249	        if (this->ir == jtag_ir::idcode) {
250	          this->dr = idcode;
251	          this->dr_length = 32;
252	        } else if (this->ir == jtag_ir::bypass) {
253	          this->dr = 0;
254	          this->dr_length = 1;
255	        } else if (this->ir == jtag_ir::dtmcs) {
256	          this->dr = this->dtmcs;
257	          this->dr_length = 32;
258	        } else if (this->ir == jtag_ir::dmi) {
259	          handle_dmi_status();
260	          this->dr = this->dmi;
261	          this->dr_length = 34 + abits;
262	        } else {
263	          spdlog::error("capture_dr: unknown ir: {:#x}", uint8_t(this->ir));
264	          return;
265	        }
266	        spdlog::trace("capture_dr: {:#x}", uint64_t(this->dr));
267	      } else if (this->state == jtag_state::shift_ir) {
268	        this->tdo = (uint8_t(ir) & 1) == 1;
269	      } else if (this->state == jtag_state::shift_dr) {
270	        this->tdo = (dr & 1) == 1;
271	      } else if (this->state == jtag_state::update_ir) {
272	        // spdlog::trace("update_ir: {:#x}", uint8_t(this->ir));
273	      } else if (this->state == jtag_state::update_dr) {
274	        // spdlog::trace("update_dr: {:#x}", uint64_t(this->dr));
275	        if (this->ir == jtag_ir::dtmcs) {
276	          if (((this->dr >> 17) & 1) == 1) {
277	            hardreset();
278	          } else if (((this->dr >> 16) & 1) == 1) {
279	            // TODO: dmireset();
280	          }
281	        } else if (this->ir == jtag_ir::dmi) {
282	          handle_dmi_op();
283	        }
284	      }
285	    }
286	  }
287	
288	  void try_accept_socket()
289	  {
290	    if (this->socket) {
291	      spdlog::warn(
292	        "jtag_dtm: calling try_accept_socket() when a socket is already connected");
293	      return;
294	    }
295	
296	    auto socket = tcp::socket{asio::system_executor{}};
297	    auto ec = boost::system::error_code{};
298	    this->acceptor.accept(socket, ec);
299	    if (ec == asio::error::try_again)
300	      return;
301	
302	    if (ec)
303	      throw std::system_error{ec, "accept"};
304	
305	    socket.non_blocking(true);
306	    spdlog::info("jtag_dtm: accepted connection from {}:{}",
307	                 socket.remote_endpoint().address().to_string(),
308	                 socket.remote_endpoint().port());
309	    this->socket = std::move(socket);
310	  }
311	
312	  void tick()
313	  {
314	    if (this->socket) {
315	      if (this->recv_buf.empty()) {
316	        auto ec = boost::system::error_code{};
317	        const auto n =
318	          this->socket->read_some(asio::buffer(recv_buf_array), ec);
319	        if (ec == asio::error::try_again)
320	          return;
321	
322	        if (ec == asio::error::eof) {
323	          this->socket.reset();
324	          return;
325	        }
326	
327	        if (ec)
328	          throw std::system_error{ec, "read"};
329	
330	        this->recv_buf = std::span{recv_buf_array.data(), n};
331	        // spdlog::debug(
332	        //   "jtag_dtm: received: {}",
333	        //   std::string_view{this->recv_buf.data(), this->recv_buf.size()});
334	      }
335	
336	      auto write_buf = std::vector<char>{};
337	      while (!this->recv_buf.empty()) {
338	        const auto c = this->recv_buf.front();
339	        this->recv_buf = this->recv_buf.subspan<1>();
340	        switch (c) {
341	        case 'B':
342	          // spdlog::trace("jtag_dtm: blink on");
343	          break;
344	        case 'b':
