#ifndef JTAG_DTM_HPP
#define JTAG_DTM_HPP

#include "utils/ahb.hpp"

#include <boost/asio.hpp>
#include <spdlog/spdlog.h>
#include <systemc>

#include <cstdint>

#include <string_view>
#include <system_error>

namespace asio = boost::asio;
namespace ip = asio::ip;
using asio::ip::tcp;

enum class jtag_state
{
  test_logic_reset,
  run_test_idle,
  select_dr_scan,
  capture_dr,
  shift_dr,
  exit1_dr,
  pause_dr,
  exit2_dr,
  update_dr,
  select_ir_scan,
  capture_ir,
  shift_ir,
  exit1_ir,
  pause_ir,
  exit2_ir,
  update_ir,
};

enum class jtag_ir : uint8_t
{
  idcode = 0x1,
  dtmcs = 0x10,
  dmi = 0x11,
  bypass = uint8_t(-1),
};

constexpr auto jtag_state_transitions =
  std::array<std::array<jtag_state, 2>, 16>{{
    // clang-format off
    {jtag_state::run_test_idle, jtag_state::test_logic_reset}, // test_logic_reset
    {jtag_state::run_test_idle, jtag_state::select_dr_scan}, // run_test_idle
    {jtag_state::capture_dr, jtag_state::select_ir_scan}, // select_dr_scan
    {jtag_state::shift_dr, jtag_state::exit1_dr}, // capture_dr
    {jtag_state::shift_dr, jtag_state::exit1_dr}, // shift_dr
    {jtag_state::pause_dr, jtag_state::update_dr}, // exit1_dr
    {jtag_state::pause_dr, jtag_state::exit2_dr}, // pause_dr
    {jtag_state::shift_dr, jtag_state::update_dr}, // exit2_dr
    {jtag_state::run_test_idle, jtag_state::select_dr_scan}, // update_dr
    {jtag_state::capture_ir, jtag_state::test_logic_reset}, // select_ir_scan
    {jtag_state::shift_ir, jtag_state::exit1_ir}, // capture_ir
    {jtag_state::shift_ir, jtag_state::exit1_ir}, // shift_ir
    {jtag_state::pause_ir, jtag_state::update_ir}, // exit1_ir
    {jtag_state::pause_ir, jtag_state::exit2_ir}, // pause_ir
    {jtag_state::shift_ir, jtag_state::update_ir}, // exit2_ir
    {jtag_state::run_test_idle, jtag_state::select_dr_scan} // update_ir
    // clang-format on
  }}; // update_ir

enum class dmi_op_operation
{
  nop = 0,
  read = 1,
  write = 2,
  reserved = 3,
};

constexpr static inline auto
to_string(const dmi_op_operation op) -> std::string_view
{
  switch (op) {
  case dmi_op_operation::nop:
    return "nop";
  case dmi_op_operation::read:
    return "read";
  case dmi_op_operation::write:
    return "write";
  case dmi_op_operation::reserved:
    return "reserved";
  default:
    __builtin_unreachable();
  }
}

enum class dmi_op_status
{
  success = 0,
  reserved = 1,
  failed = 2,
  busy = 3,
};

constexpr static inline auto
to_string(const dmi_op_status status) -> std::string_view
{
  switch (status) {
  case dmi_op_status::success:
    return "success";
  case dmi_op_status::reserved:
    return "reserved";
  case dmi_op_status::failed:
    return "failed";
  case dmi_op_status::busy:
    return "busy";
  default:
    __builtin_unreachable();
  }
}
struct jtag_dtm : sc_core::sc_module
{
  // (mfg: 0x31e (Andes Technology Corporation), part: 0x0005, ver: 0x1)
  static constexpr auto idcode = 0x1000563d;
  static constexpr auto ir_length = 5;
  static constexpr auto abits = 7;

  using ahb_manager = ahb::manager<abits + 2, 32>;

  ahb_manager& ahb;

  std::optional<tcp::socket> socket{};
  tcp::acceptor acceptor{asio::system_executor{}};
  std::array<char, 4096> recv_buf_array{};
  std::span<char> recv_buf{};

  jtag_state state;
  bool tck, tdo;
  // two shift registers : ir, dr
  jtag_ir ir;
  uint64_t dr;
  size_t dr_length;
  uint32_t dtmcs;
  uint64_t dmi;

  sc_core::sc_in<bool> clk{"clk"};
  using SC_CURRENT_USER_MODULE = jtag_dtm;

  void hardreset()
  {
    // spdlog::trace("DTMCS hardreset");
    state = jtag_state::test_logic_reset;
    tck = false, tdo = false;
    ir = jtag_ir::idcode;
    dr = 0;
    dr_length = 64;
    // version (0: v0.11, 1: v0.13 and v1.0)
    // idle (stay in idle mode for 6 cycles in each scan)
    dtmcs = uint32_t(1) << 0 // version
          | uint32_t(abits) << 4 // abits
          | uint32_t(7) << 12; // idle
    static_assert(34 + abits <= 64);
    dmi = 0;
    recv_buf_array = {};
    recv_buf = {};
    if (this->socket && this->socket->is_open()) {
      this->socket->shutdown(boost::asio::ip::tcp::socket::shutdown_both);
      this->socket->close();
      this->socket = std::nullopt;
    }
  }

  jtag_dtm(const sc_core::sc_module_name& name, ahb_manager& ahb)
      : sc_core::sc_module{name}, ahb{ahb}
  {
    hardreset();
    SC_METHOD(tick);
    this->sensitive << clk.pos();
  }

  void init_port(const uint16_t port)
  {
    const auto endpoint = tcp::endpoint(ip::make_address("127.0.0.1"), port);
    this->acceptor.open(endpoint.protocol());
    this->acceptor.set_option(tcp::acceptor::reuse_address(true));
    // TODO: change it to blocking mode ?
    this->acceptor.non_blocking(true);
    this->acceptor.bind(endpoint);
    this->acceptor.listen();
    spdlog::info("jtag_dtm: listening on 127.0.0.1:{}", port);
  }

  [[nodiscard]]
  auto is_connected() const -> bool
  {
    return this->socket.has_value();
  }

  void handle_dmi_status()
  {
    if (this->ahb.txn.is_busy()) {
      this->dmi = uint64_t(dmi_op_status::busy);
    } else if (this->ahb.txn.phase == ahb_manager::transaction::phase::error) {
      this->dmi = uint64_t(dmi_op_status::failed);
    } else {
      this->dmi = uint64_t(dmi_op_status::success);
    }
    this->dmi |= (uint64_t(this->ahb.txn.addr) >> 2) << 34
               | uint64_t(this->ahb.txn.data) << 2;
    // spdlog::trace("dmi: status={}, addr={:#x}, data={:#x}", this->dmi & 0b11,
    // this->ahb.txn.addr.to_uint64() >> 2,
    // this->ahb.txn.data.to_uint64());
  }
  void handle_dmi_op()
  {
    this->dmi = this->dr;
    const auto op = this->dmi & 0b11;
    const auto data = (this->dmi >> 2) & 0xffffffff;
    const auto addr = (this->dmi >> 34) & ((uint64_t{1} << abits) - 1);
    // spdlog::trace("dmi: op={}, addr={:#x}, data={:#x}", op, addr, data);
    if (op == 1) { // read
      assert(!this->ahb.txn.is_busy());
      this->ahb.read(addr << 2);
    } else if (op == 2) { // write
      assert(!this->ahb.txn.is_busy());
      ahb.write(addr << 2, data);
    }
  }

  void set_tck_tms_tdi(const bool tck, const bool tms, const bool tdi)
  {
    if (tck == this->tck)
      return;

    this->tck = tck;

    if (tck) { // rising edge
      if (this->state == jtag_state::shift_ir) {
        this->ir = jtag_ir((uint8_t) (uint8_t(this->ir) >> 1)
                           | (uint8_t(tdi) << (ir_length - 1)));
      } else if (this->state == jtag_state::shift_dr) {
        this->dr = (this->dr >> 1) | (uint64_t(tdi) << (dr_length - 1));
      }
      this->state = jtag_state_transitions[size_t(this->state)][size_t(tms)];
    } else { // falling edge
      if (this->state == jtag_state::test_logic_reset) {
        // spdlog::trace("test_logic_reset");
        this->ir = jtag_ir::idcode;
      } else if (this->state == jtag_state::run_test_idle) {
        // spdlog::debug("run_test_idle");
      } else if (this->state == jtag_state::capture_dr) {
        if (this->ir == jtag_ir::idcode) {
          this->dr = idcode;
          this->dr_length = 32;
        } else if (this->ir == jtag_ir::bypass) {
          this->dr = 0;
          this->dr_length = 1;
        } else if (this->ir == jtag_ir::dtmcs) {
          this->dr = this->dtmcs;
          this->dr_length = 32;
        } else if (this->ir == jtag_ir::dmi) {
          handle_dmi_status();
          this->dr = this->dmi;
          this->dr_length = 34 + abits;
        } else {
          spdlog::error("capture_dr: unknown ir: {:#x}", uint8_t(this->ir));
          return;
        }
        spdlog::trace("capture_dr: {:#x}", uint64_t(this->dr));
      } else if (this->state == jtag_state::shift_ir) {
        this->tdo = (uint8_t(ir) & 1) == 1;
      } else if (this->state == jtag_state::shift_dr) {
        this->tdo = (dr & 1) == 1;
      } else if (this->state == jtag_state::update_ir) {
        // spdlog::trace("update_ir: {:#x}", uint8_t(this->ir));
      } else if (this->state == jtag_state::update_dr) {
        // spdlog::trace("update_dr: {:#x}", uint64_t(this->dr));
        if (this->ir == jtag_ir::dtmcs) {
          if (((this->dr >> 17) & 1) == 1) {
            hardreset();
          } else if (((this->dr >> 16) & 1) == 1) {
            // TODO: dmireset();
          }
        } else if (this->ir == jtag_ir::dmi) {
          handle_dmi_op();
        }
      }
    }
  }

  void try_accept_socket()
  {
    if (this->socket) {
      spdlog::warn(
        "jtag_dtm: calling try_accept_socket() when a socket is already connected");
      return;
    }

    auto socket = tcp::socket{asio::system_executor{}};
    auto ec = boost::system::error_code{};
    this->acceptor.accept(socket, ec);
    if (ec == asio::error::try_again)
      return;

    if (ec)
      throw std::system_error{ec, "accept"};

    socket.non_blocking(true);
    spdlog::info("jtag_dtm: accepted connection from {}:{}",
                 socket.remote_endpoint().address().to_string(),
                 socket.remote_endpoint().port());
    this->socket = std::move(socket);
  }

  void tick()
  {
    if (this->socket) {
      if (this->recv_buf.empty()) {
        auto ec = boost::system::error_code{};
        const auto n =
          this->socket->read_some(asio::buffer(recv_buf_array), ec);
        if (ec == asio::error::try_again)
          return;

        if (ec == asio::error::eof) {
          this->socket.reset();
          return;
        }

        if (ec)
          throw std::system_error{ec, "read"};

        this->recv_buf = std::span{recv_buf_array.data(), n};
        // spdlog::debug(
        //   "jtag_dtm: received: {}",
        //   std::string_view{this->recv_buf.data(), this->recv_buf.size()});
      }

      auto write_buf = std::vector<char>{};
      while (!this->recv_buf.empty()) {
        const auto c = this->recv_buf.front();
        this->recv_buf = this->recv_buf.subspan<1>();
        switch (c) {
        case 'B':
          // spdlog::trace("jtag_dtm: blink on");
          break;
        case 'b':
          // spdlog::trace("jtag_dtm: blink off");
          break;
        case 'R':
          write_buf.push_back(this->tdo ? '1' : '0');
          break;
        case 'Q':
          spdlog::info("jtag_dtm: quit request received");
          this->socket.reset();
          break;
        case '0':
          set_tck_tms_tdi(false, false, false);
          break;
        case '1':
          set_tck_tms_tdi(false, false, true);
          break;
        case '2':
          set_tck_tms_tdi(false, true, false);
          break;
        case '3':
          set_tck_tms_tdi(false, true, true);
          break;
        case '4':
          set_tck_tms_tdi(true, false, false);
          break;
        case '5':
          set_tck_tms_tdi(true, false, true);
          break;
        case '6':
          set_tck_tms_tdi(true, true, false);
          break;
        case '7':
          set_tck_tms_tdi(true, true, true);
          break;
        case 'r':
          spdlog::info("jtag_dtm: reset request received");
          this->state = jtag_state::test_logic_reset;
          // TODO: reset
          break;
        default:
          spdlog::error("jtag_dtm: unimplemented request: {}", c);
          break;
        }

        if (this->tck && this->state == jtag_state::run_test_idle)
          break;
      }

      if (!write_buf.empty() && this->socket) {
        asio::write(this->socket.value(), asio::buffer(write_buf));
      }
    } else if (this->acceptor.is_open()) {
      try_accept_socket();
      return;
    }
  }
};

#endif

