#ifndef NX45V_CPU_CLUSTER_SUBSYSTEM_HPP
#define NX45V_CPU_CLUSTER_SUBSYSTEM_HPP

#include "pybind11.hpp"
#include "signals/internal_signals_nx45v.hpp"
#include "utils/ahb.hpp"
#include "utils/axi.hpp"
#include "utils/cpu_signal_registry.hpp"
#include "utils/duplicator.hpp"
#include "utils/signals.hpp"

#include <axi/pin/axi4_target.h>
#include <systemc>
#include <Vnx45v_plain.h>

#include <cstddef>

#include <array>

struct nx45v_cpu_cluster_subsystem
    : public Vnx45v_plain,
      public CpuSignalRegistry<nx45v_cpu_cluster_subsystem>
{
public:
  using SC_CURRENT_USER_MODULE = nx45v_cpu_cluster_subsystem;

  nx45v_cpu_cluster_subsystem(const sc_core::sc_module_name& name = "nx45v")
      : Vnx45v_plain{name}
  {}

#define VERILOG_DEFINE(key, value) static constexpr auto key = value;
#include <Vnx45v_plain_config.h>

  static constexpr auto SYSTEM_BUS_TYPE = BusTypes::AXI;

  static constexpr auto dmi_addr_width = 9;
  static constexpr auto dmi_data_width = 32;
  static constexpr auto has_shared_cache = (NDS_L2C_CACHE_SIZE_KB > 0);

  using Vnx45v_plain::contextp;
  using Vnx45v_plain::final;
  using Vnx45v_plain::modelName;
  using Vnx45v_plain::threads;
  using Vnx45v_plain::trace;

  using Vnx45v_plain::hart0_trace_cause;
  using Vnx45v_plain::hart0_trace_tval;

  using bus_cfg =
    axi::axi4_cfg<NDS_BIU_DATA_WIDTH, NDS_BIU_ADDR_WIDTH, NDS_BIU_ID_WIDTH, 1>;

  axi_signals<bus_cfg> mem{"mem"};
  axi_signals<bus_cfg> mmio{"mmio"};

  axi::pin::axi4_target<bus_cfg> mem_bfm{"mem_bfm"};
  axi::pin::axi4_target<bus_cfg> mmio_bfm{"mmio_bfm"};

  // if NDS_PC_GPR_PROBING_SUPPORT_INT == 1, TODO: conditional compiled ?
  sc_core::sc_signal<vlpin<NDS_VALEN>> current_pc{"current_pc", 0};
  sc_core::sc_signal<vlpin<NDS_XLEN>> gpr_value{"gpr_value", 0};
  sc_core::sc_signal<vlpin<13>> gpr_index{"gpr_index", 0};

  UintToBool<NDS_NHART> reset_narrow{"reset_narrow"};
  sc_core::sc_signal<bool> resetn_bool;

  auto bind(
    const sc_core::sc_clock& clk,
    const sc_core::sc_signal<sc_dt::sc_uint<NDS_NHART>>& reset,
    std::array<sc_core::sc_signal<vlpin<NDS_VALEN>>, NDS_NHART>& reset_vector,
    ahb::signals<dmi_addr_width, dmi_data_width>& dmi,
    sc_core::sc_signal<bool>& wfi_signal,
    sc_core::sc_signal<sc_dt::sc_uint<31>>& int_trigger)
  {
    reset_narrow.sig_in.bind(reset);
    reset_narrow.sig_out.bind(resetn_bool);
    this->mem_bfm.clk_i.bind(clk);
    this->mmio_bfm.clk_i.bind(clk);

    this->mem_bfm.bind_ar(this->mem);
    this->mem_bfm.bind_r(this->mem);
    this->mem_bfm.bind_aw(this->mem);
    this->mem_bfm.bind_w(this->mem);
    this->mem_bfm.bind_b(this->mem);

    this->mmio_bfm.bind_ar(this->mmio);
    this->mmio_bfm.bind_r(this->mmio);
    this->mmio_bfm.bind_aw(this->mmio);
    this->mmio_bfm.bind_w(this->mmio);
    this->mmio_bfm.bind_b(this->mmio);

#define X(ch, name) \
  this->mem_##ch##name.bind(this->mem.ch##_##name); \
  this->mmio_##ch##name.bind(this->mmio.ch##_##name);

    EXPAND_AXI4_SIGNALS

#undef X

#define X(name) this->dmi_##name.bind(dmi.name);
    EXPAND_AHB_SIGNALS_NO_HREADY
#undef X
    this->dmi_hreadyout.bind(dmi.hready);

    this->dmi_hsel.bind(signals::one);
    this->dmi_hready.bind(signals::one);

    this->aclk.bind(clk);
    this->core_clk.bind(clk);
    this->dc_clk.bind(clk);
    this->l2_clk.bind(clk);
    this->lm_clk.bind(clk);
    this->mtime_clk.bind(clk);
    this->vpu_clk.bind(clk);
    this->vpu_vace_clk.bind(clk);
    this->vpu_valu_clk.bind(clk);
    this->vpu_vdiv_clk.bind(clk);
    this->vpu_vfdiv_clk.bind(clk);
    this->vpu_vfmis_clk.bind(clk);
    this->vpu_vlsu_clk.bind(clk);
    this->vpu_vmac_clk.bind(clk);
    this->vpu_vmask_clk.bind(clk);
    this->vpu_vpermut_clk.bind(clk);
    this->vpu_vsp_clk.bind(clk);

    this->aresetn.bind(resetn_bool);
    this->core_l2_resetn.bind(resetn_bool);
    this->core_resetn.bind(resetn_bool);
    this->dmi_resetn.bind(resetn_bool);
    this->l2_resetn.bind(resetn_bool);
    this->por_rstn.bind(resetn_bool);
    this->slvp_resetn.bind(resetn_bool);
    this->test_rstn.bind(resetn_bool);

    this->hart0_reset_vector.bind(reset_vector[0]);

    this->hart0_trace_enabled.bind(signals::one);
    this->axi_bus_clk_en.bind(signals::one);
    this->test_mode(signals::zero);
    this->scan_enable(signals::zero);

    // ACE Streaming Port (ASP)
    signals::ignore(this->hart0_cp_cpu_rdata);
    signals::ignore(this->hart0_cp_cpu_rdata_ready);
    signals::ignore(this->hart0_cp_cpu_rdata_valid);
    signals::ignore(this->hart0_cpu_cp_wdata);
    signals::ignore(this->hart0_cpu_cp_wdata_bwe);
    signals::ignore(this->hart0_cpu_cp_wdata_ready);
    signals::ignore(this->hart0_cpu_cp_wdata_valid);

    signals::ignore(this->dbg_srst_req);
    signals::ignore(this->dmactive);
    signals::ignore(this->hart0_dcache_disable_init);
    signals::ignore(this->hart0_icache_disable_init);
    signals::ignore(this->hart0_nmi);
    signals::ignore(this->hart0_trace_cause);
    signals::ignore(this->hart0_trace_halted);
    signals::ignore(this->hart0_trace_iaddr);
    signals::ignore(this->hart0_trace_ilastsize);
    signals::ignore(this->hart0_trace_iretire);
    signals::ignore(this->hart0_trace_itype);
    signals::ignore(this->hart0_trace_priv);
    signals::ignore(this->hart0_trace_reset);
    signals::ignore(this->hart0_trace_trigger);
    signals::ignore(this->hart0_trace_tval);
    signals::ignore(this->hart0_wakeup_event);
    signals::ignore(this->l2c_err_int);
    signals::ignore(this->vpu_clk_en);
    signals::ignore(this->vpu_vace_clk_en);
    signals::ignore(this->vpu_valu_clk_en);
    signals::ignore(this->vpu_vdiv_clk_en);
    signals::ignore(this->vpu_vfdiv_clk_en);
    signals::ignore(this->vpu_vfmis_clk_en);
    signals::ignore(this->vpu_vlsu_clk_en);
    signals::ignore(this->vpu_vmac_clk_en);
    signals::ignore(this->vpu_vmask_clk_en);
    signals::ignore(this->vpu_vpermut_clk_en);
    signals::ignore(this->vpu_vsp_clk_en);
    this->int_src.bind(int_trigger);
    this->hart0_core_wfi_mode.bind(wfi_signal);

    if constexpr (NDS_PC_GPR_PROBING_SUPPORT_INT == 1) {
      this->hart0_probe_current_pc.bind(current_pc);
      this->hart0_probe_selected_gpr_value(gpr_value);
      this->hart0_probe_gpr_index.bind(gpr_index);
    }
  }

  template<int Enabled = NDS_PC_GPR_PROBING_SUPPORT_INT>
  uint64_t get_current_pc()
    requires(Enabled == 1)
  {
    return current_pc.read();
  }

  template<int Enabled = NDS_PC_GPR_PROBING_SUPPORT_INT>
  uint32_t get_gpr(uint16_t idx)
    requires(Enabled == 1)
  {
    gpr_index.write(idx);
    return gpr_value.read();
  }

  static CpuSignalRegistry<nx45v_cpu_cluster_subsystem>::Registry
  build_signal_registry()
  {
    using Self = nx45v_cpu_cluster_subsystem;
    CpuSignalRegistry<Self>::Registry reg;

#if defined(EXPAND_INTERNAL_SIGNALS)
#define X(name, signal) \
  reg.emplace(#name, [](const Self& s) -> uint64_t { \
    return widen_to_u64(s.rootp->signal); \
  });
    EXPAND_INTERNAL_SIGNALS
    EXPAND_VPU_INTERNAL_SIGNALS
#undef X
#endif // EXPAND_INTERNAL_SIGNALS

#if defined(EXPAND_INTERNAL_MASKED_SIGNALS)
#define X(name, signal, shift, mask) \
  reg.emplace(#name, [](const Self& s) -> uint64_t { \
    return static_cast<uint64_t>((s.rootp->signal >> (shift)) & (mask)); \
  });
    EXPAND_INTERNAL_MASKED_SIGNALS
#undef X
#endif // EXPAND_INTERNAL_MASKED_SIGNALS

    // decode[36] = write to mask register
    // decode[47] = reduction, write to single vd
    // decode[50] = move op, write to single vd
    reg.emplace("i0_write_whole_vd", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 4) & 0x1) | ((d[1] >> 15) & 0x1) | ((d[1] >> 18) & 0x1);
    });

    reg.emplace("i1_write_whole_vd", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 4) & 0x1) | ((d[1] >> 15) & 0x1) | ((d[1] >> 18) & 0x1);
    });

    // decode[46:44] = vd whole register
    reg.emplace("i0_whole_vd_num", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 12) & 0b111) + 1;
    });

    reg.emplace("i1_whole_vd_num", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 12) & 0b111) + 1;
    });

    // decode[20] = rd1 write enable
    reg.emplace("i0_rd1_wen", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[0] >> 20) & 0b1);
    });

    reg.emplace("i1_rd1_wen", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[0] >> 20) & 0b1);
    });

    // decode[52] = vd_x2, widening instr
    reg.emplace("i0_vd_x2", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 20) & 0b1);
    });

    reg.emplace("i1_vd_x2", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__u_vpu__DOT__u_vdis__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 20) & 0b1);
    });

    return reg;
  }

#if ENABLE_PYBIND11
  static void bind_pybind11(pybind11::module_& m)
  {
    auto c = pybind11::class_<nx45v_cpu_cluster_subsystem>(
      m, "nx45v_cpu_cluster_subsystem");
    bind_registry_to_pybind11(c);
  }
#endif // ENABLE_PYBIND11
